VALUES
  ('aboriginal-a5729396-moex-00224', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '主管機關依法進行原住民族文化資產指定、登錄之審議前，應依據文化資產類別、文化特性與民族屬 性組成專案小組，就審議項目與基準，及指定登錄範圍影響進行評估。前項專案小組代表中具原住民 身分者，不得少於專案小組全體成員的比例為何？', '["三分之一", "二分之一", "四分之一", "五分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00225', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '有關原住民族無形文化資產之保存維護，主管機關應會商所屬原住民族、部落或其他傳統組織，訂定 保存維護計畫，就其中瀕臨滅失者詳細製作紀錄、傳習，或採取為保存維護所需之適當措施，並得委 託那些單位進行保存及維護？', '["部落公法人、社團法人或財團法人", "部落公法人、民族議會或原住民族委員會原住民族發展文化中心", "部落公法人、鄉鎮區公所或直轄市、縣市文化局處", "部落公法人、直轄市、縣市文化局處或原住民族委員會原住民族發展文化中心"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00226', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族文化資產處理辦法之內容，就考古遺址監管保護規定之敘述，下列何者錯誤？', '["主管機關進行考古遺址監管保護，應會商當地原住民族、部落或其他傳統組織", "主管機關得委託部落公法人、社團法人或財團法人參與考古遺址監管保護計畫之訂定、執行與管理", "考古遺址所在之原住民族、部落或其他傳統組織，享有日常近用考古遺址與檢視、察考考古遺址之 權利", "主管機關對人員出入原住民族考古遺址之管制或對當地社群近用考古遺址之限制，應尊重當地原住 民族信仰、傳統習慣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00227', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據國土計畫法第44條之規定，中央主管機關應設置國土永續發展基金；下列何者不是其基金來源？', '["使用許可案件所收取之國土保育費", "自來水事業機構附徵之一定比率費用", "電力事業機構附徵之一定比率費用", "公益彩券回饋金盈餘分配"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00228', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族委員會就業歧視及勞資糾紛法律扶助辦法，原住民在工作職場發生就業歧視或勞資糾 紛，各級主管機關應給予法律諮詢以及提供律師及必要之訴訟費用。請問該辦法是依據下列那一部法 規範制定的？', '["中華民國憲法", "原住民族基本法", "原住民族工作權保障法", "法律扶助法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00229', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '原住民族健康法由朝野黨團、公私團體及行政部門歷經多年來的共同努力，於民國112年5月完成三 讀，是我國落實原住民族健康權、改善醫療照護不均等的重大里程碑。使原住民族健康權實踐從「計 畫層次」提升為「法律位階」，下列何者非該法的特色？', '["指定專責單位辦理原住民族健康事務", "明定召開原住民族健康政策會及其任務：強調擴大原住民族參與政策制定，且規範具原住民身分之 委員不得少於二分之一", "定期調查與研究原住民族健康狀況及需求，建置健康資料庫", "普及原住民族鄉鎮地區的醫院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00230', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例規定，智慧創作專用權人之權利被侵害時，得請求排除之，若造 成專用權人之損害，得請求損害賠償。在被害人（專用權人）不易證明其實際損害額者，得請求法院 依侵害情節，酌定多少元的損害賠償？', '["新臺幣五萬元以上一百萬元以下", "新臺幣五萬元以上二百萬元以下", "新臺幣五萬元以上三百萬元以下", "新臺幣五萬元以上五百萬元以下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00231', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '為促進原住民保留地開發、原住民族文化保存、醫療保健、社會福利、郵電運輸、金融服務及其他經 中央主管機關核定事業，優先輔導原住民或原住民機構、法人或團體開發或興辦。法人或團體申請租 用原住民保留地，每一租期不得超過幾年？', '["五年", "八年", "九年", "十年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00232', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民保留地開發管理辦法之規定，原住民申請無償取得原住民保留地所有權之土地面積最高限 額，下列敘述何者正確？', '["依區域計畫法編定為農牧用地、養殖用地或依都市計畫法劃定為農業區、保護區並供農作、養殖或 畜牧使用土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人五公頃", "依法得為建築使用之土地，每戶一公頃", "原住民申請無償取得前項第一款及第二款土地得合併計算面積，其比率由中央主管機關定之。但基 於地形限制，得百分之百增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00233', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '目前具原住民身分之教育師資不足，依據原住民族教育法第32條，下列內容何者有誤？', '["高級中等以下學校民族教育教師培育及資格之取得，依師資培育法及其相關法規之規定辦理", "中央教育主管機關得協調師資培育之大學，辦理師資職前教育課程，提供於原住民重點學校或偏遠 地區學校實際從事族語教學工作滿四學期且現職之族語老師、族語教學支援工作人員或代理教師進 修機會", "修畢師資職前教育課程成績及格者，由師資培育之大學發給修畢師資職前教育證明書", "經甄選獲聘任為原住民重點學校或偏遠地區學校編制內合格專任教師者，應任教民族教育課程至少 三年，始得提出申請介聘"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
